using System.Diagnostics;
using TextAnalysis;

// Setup
var words = new[] { "the", "quick", "brown", "fox", "jumps", "over", "the", "lazy", "dog",
    "performance", "benchmarking", "is", "important", "for", "understanding", "runtime", "behavior",
    "dotnet", "framework", "provides", "excellent", "tooling", "and", "libraries" };
var rng = new Random(42);
var parts = new string[1000];
for (int i = 0; i < parts.Length; i++)
    parts[i] = words[rng.Next(words.Length)];
var analyzer = new TextAnalyzer(string.Join(" ", parts));

const int WarmupIterations = 100;
const int BenchmarkIterations = 100_000;

Console.WriteLine($"Runtime: {Environment.Version}");
Console.WriteLine($"Framework: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Iterations: {BenchmarkIterations:N0}");
Console.WriteLine();

// Warmup & Benchmark helper
void Bench(string name, Action action)
{
    // Warmup
    for (int i = 0; i < WarmupIterations; i++) action();
    GC.Collect();
    GC.WaitForPendingFinalizers();
    GC.Collect();

    // Multiple runs to get stable stats
    var times = new double[5];
    for (int run = 0; run < 5; run++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < BenchmarkIterations; i++) action();
        sw.Stop();
        times[run] = sw.Elapsed.TotalMilliseconds / BenchmarkIterations * 1_000_000; // ns per op
    }
    Array.Sort(times);
    double median = times[2];
    double min = times[0];
    double max = times[4];
    Console.WriteLine($"  {name,-25} | Median: {median,8:F1} ns | Min: {min,8:F1} ns | Max: {max,8:F1} ns");
}

Console.WriteLine("| Method                    | Median (ns) | Min (ns)  | Max (ns)  |");
Console.WriteLine("|---------------------------|-------------|-----------|-----------|");

Bench("AverageWordLength", () => analyzer.AverageWordLength());
Bench("WordLengthHistogram", () => analyzer.WordLengthHistogram());
